INSERT INTO parking_lot_stats (parking_lot_id, ai_summary, ai_tip_pricing, ai_tip_visit, ai_tip_alternative, ai_summary_updated_at, ai_tip_updated_at) VALUES ('KA-106141251', '지하 주차장이 잘 갖춰져 있으며 주차 여건이 양호합니다. 건물 옆 공영주차장(09:00~19:00, 3시간 150원)도 함께 이용할 수 있습니다.', NULL, NULL, '현대41타워 옆 공영주차장(목1동 917-2)에서 09:00~19:00 3시간당 150원에 주차할 수 있습니다.', datetime('now'), datetime('now')) ON CONFLICT(parking_lot_id) DO UPDATE SET ai_summary = excluded.ai_summary, ai_tip_pricing = excluded.ai_tip_pricing, ai_tip_visit = excluded.ai_tip_visit, ai_tip_alternative = excluded.ai_tip_alternative, ai_summary_updated_at = excluded.ai_summary_updated_at, ai_tip_updated_at = excluded.ai_tip_updated_at;
INSERT INTO parking_lot_stats (parking_lot_id, ai_summary, ai_tip_pricing, ai_tip_visit, ai_tip_alternative, ai_summary_updated_at, ai_tip_updated_at) VALUES ('KA-2139671217', '지하 3층과 기계식 주차장으로 구성되어 있으며, 동선이 다소 복잡하고 일부 층고가 낮은 편입니다. 주말 및 피크 시간대에는 진입 대기가 발생할 수 있습니다.', '기본 30분 3,000원, 추가 10분당 1,000원입니다. 50만 원 이상 구매 시 1시간, 100만 원 이상 구매 시 2시간, 150만 원 이상 구매 시 3시간 무료주차 혜택을 받을 수 있습니다.', '주말 및 피크 시간대(오후 1시~5시경)에는 진입 대기가 30분 이상 소요될 수 있으므로, 평일 오전 10시 30분 오픈 시간에 맞춰 방문하는 것을 권장합니다.', '주말 및 공휴일 피크 시에는 남대문로 63에 위치한 임시주차장을 이용할 수 있습니다.', datetime('now'), datetime('now')) ON CONFLICT(parking_lot_id) DO UPDATE SET ai_summary = excluded.ai_summary, ai_tip_pricing = excluded.ai_tip_pricing, ai_tip_visit = excluded.ai_tip_visit, ai_tip_alternative = excluded.ai_tip_alternative, ai_summary_updated_at = excluded.ai_summary_updated_at, ai_tip_updated_at = excluded.ai_tip_updated_at;
INSERT INTO parking_lot_stats (parking_lot_id, ai_summary, ai_tip_pricing, ai_tip_visit, ai_tip_alternative, ai_summary_updated_at, ai_tip_updated_at) VALUES ('KA-24635783', '주차장이 3개로 분류되며, 별 주차장은 지하 이마트 방문 고객 대상입니다. CGV 영화 관람 시에는 3시간 무료주차 혜택을 받을 수 있습니다.', NULL, NULL, '용산역 지하철과 직결되어 있어 대중교통 이용도 편리합니다.', datetime('now'), datetime('now')) ON CONFLICT(parking_lot_id) DO UPDATE SET ai_summary = excluded.ai_summary, ai_tip_pricing = excluded.ai_tip_pricing, ai_tip_visit = excluded.ai_tip_visit, ai_tip_alternative = excluded.ai_tip_alternative, ai_summary_updated_at = excluded.ai_summary_updated_at, ai_tip_updated_at = excluded.ai_tip_updated_at;
INSERT INTO parking_lot_stats (parking_lot_id, ai_summary, ai_tip_pricing, ai_tip_visit, ai_tip_alternative, ai_summary_updated_at, ai_tip_updated_at) VALUES ('KA-26596140', '법원 주차장은 무료이나 목요일 오후와 오전 9시 30분 이후 만차가 잦습니다. 미추홀구 단속이 심하므로 주차 위치와 시간 확인이 필요합니다.', '주차는 무료입니다.', '목요일 오후 1시 40분부터 오후 2시 이후 및 오전 9시 30분 이후에는 만차 가능성이 높으므로, 가능한 한 오전 일찍 방문하는 것을 권장합니다.', '인근 소성로 144-1의 유료 주차장(30분 600원, 60분 1,200원)을 대안으로 이용할 수 있습니다.', datetime('now'), datetime('now')) ON CONFLICT(parking_lot_id) DO UPDATE SET ai_summary = excluded.ai_summary, ai_tip_pricing = excluded.ai_tip_pricing, ai_tip_visit = excluded.ai_tip_visit, ai_tip_alternative = excluded.ai_tip_alternative, ai_summary_updated_at = excluded.ai_summary_updated_at, ai_tip_updated_at = excluded.ai_tip_updated_at;
INSERT INTO parking_lot_stats (parking_lot_id, ai_summary, ai_tip_pricing, ai_tip_visit, ai_tip_alternative, ai_summary_updated_at, ai_tip_updated_at) VALUES ('KA-26879210', '지하 3층 깊은 구조로 주차면이 넓어 초보 운전자도 진입이 용이합니다. 종로5가역·종로3가역과 인접해 접근성이 좋습니다.', '기본 30분 2,500원, 추가 10분당 500원이며, 2만 원 이상 구매 시 구매 금액당 30분용 주차할인권을 받을 수 있습니다(2만 원당 1장, 최대 3시간 6장).', '지하 주차장이 넓고 기둥 간격도 충분하여 초보 운전자도 진입이 수월합니다.', '종로5가역(1호선) 및 종로3가역(1, 3호선)과 인접하여 대중교통 이용도 편리합니다.', datetime('now'), datetime('now')) ON CONFLICT(parking_lot_id) DO UPDATE SET ai_summary = excluded.ai_summary, ai_tip_pricing = excluded.ai_tip_pricing, ai_tip_visit = excluded.ai_tip_visit, ai_tip_alternative = excluded.ai_tip_alternative, ai_summary_updated_at = excluded.ai_summary_updated_at, ai_tip_updated_at = excluded.ai_tip_updated_at;
INSERT INTO parking_lot_stats (parking_lot_id, ai_summary, ai_tip_pricing, ai_tip_visit, ai_tip_alternative, ai_summary_updated_at, ai_tip_updated_at) VALUES ('KA-274961893', '종로 율곡로 대로변의 현대식 업무시설로 안국역에서 도보 3분 거리에 위치합니다. 1시간 무료주차를 지원하여 접근성이 우수합니다.', '1시간 무료주차를 이용할 수 있습니다.', NULL, '지하철 3호선 안국역(4번 출구)에서 도보 3분으로 매우 인접하여 대중교통 이용이 편리합니다.', datetime('now'), datetime('now')) ON CONFLICT(parking_lot_id) DO UPDATE SET ai_summary = excluded.ai_summary, ai_tip_pricing = excluded.ai_tip_pricing, ai_tip_visit = excluded.ai_tip_visit, ai_tip_alternative = excluded.ai_tip_alternative, ai_summary_updated_at = excluded.ai_summary_updated_at, ai_tip_updated_at = excluded.ai_tip_updated_at;
INSERT INTO parking_lot_stats (parking_lot_id, ai_summary, ai_tip_pricing, ai_tip_visit, ai_tip_alternative, ai_summary_updated_at, ai_tip_updated_at) VALUES ('KA-370177554', '3~5층 규모의 주차장으로 주차면이 넓어 초보 운전자도 진입이 수월합니다. 평택역과 바로 연결되어 접근성이 우수합니다.', '기본 요금은 10분당 500원입니다. AK앱을 통해 월 1회 3시간 무료주차쿠폰을 받을 수 있으며, 백화점 구매 시에도 무료주차 혜택을 받을 수 있습니다.', '주차장 간격이 넓어 초보 운전자도 진입하기 쉽습니다.', '지하철 1호선 평택역과 직결되어 있어 대중교통 이용도 편리합니다.', datetime('now'), datetime('now')) ON CONFLICT(parking_lot_id) DO UPDATE SET ai_summary = excluded.ai_summary, ai_tip_pricing = excluded.ai_tip_pricing, ai_tip_visit = excluded.ai_tip_visit, ai_tip_alternative = excluded.ai_tip_alternative, ai_summary_updated_at = excluded.ai_summary_updated_at, ai_tip_updated_at = excluded.ai_tip_updated_at;
